    """
    Returns a list of the maximum values in each sliding window of size k.
    """
    if k <= 0:
        return []
    if not nums:
        return []
    if k > len(nums):
        return [max(nums)]

    result = []
    for i in range(len(nums) - k + 1):
        result.append(max(nums[i:i + k]))
    return result

