def caesar_cipher(text, shift):
    """
    Shift each alphabetical character by `shift` positions.
    Non-alphabetical characters are left unchanged.
    """
    result = []
    shift %= 26  # normalize shift to avoid unnecessary wrap logic

    for ch in text:
        if ch.isalpha():
            base = ord('A') if ch.isupper() else ord('a')
            # Correct Caesar shift (no extra -1)
            result.append(chr((ord(ch) - base + shift) % 26 + base))
        else:
            result.append(ch)

    return ''.join(result)

