def majority_element(nums):
    """
    Return the majority element if it exists (appears more than n//2 times),
    otherwise return -1.
    """
    n = len(nums)
    if n == 0:
        return -1

    counts = {}
    for num in nums:
        counts[num] = counts.get(num, 0) + 1
        # Majority element must appear strictly more than n//2 times
        if counts[num] > n // 2:
            return num
    return -1

