def compress_string(s):
    if not s:
        return ''
    result = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i - 1]:
            count += 1
        else:
            # Append the previous character and its count
            result.append(s[i - 1] + str(count))
            count = 1
    # Append the last run
