def find_second_largest(nums):
    """
    Returns the second largest distinct value in nums.

    Raises:
        ValueError: if there is no second distinct largest value.
    """
    if nums is None:
        raise ValueError("nums must not be None")

    first = second = float("-inf")
    for num in nums:
        if num > first:
            second = first
            first = num
        elif first != num and num > second:
            second = num

    if second == float("-inf"):
        raise ValueError("There is no second largest distinct value.")
    return second

