    Return the maximum value in a 2D matrix.

    Raises:
        ValueError: if matrix is empty or contains no elements.
    """
    if not matrix:
        raise ValueError("matrix must not be empty")

    max_val = None
    for row in matrix:
        if not row:
            continue
        row_max = max(row)
