def quicksort(arr):
    # Return a new sorted list (do not mutate input)
    if len(arr) <= 1:
        return arr

    pivot = arr[0]
    left = [x for x in arr[1:] if x <= pivot]
    right = [x for x in arr[1:] if x > pivot]

    # Ensure duplicates of the pivot are preserved
    return quicksort(left) + [pivot] + quicksort(right)

